ValidationRule.errorConditionFormula:
AND( NOT(CONTAINS($Profile.Name, "Admin")), ISPICKVAL(OpenSource__c, 'Manual'),
OR(
/* Bloqueia edição do status pelo criador */ AND( ISCHANGED(Status__c), $User.Id = CreatedById),
/* Bloqueia criação com status diferente de "Nova" */ AND( ISNEW(), NOT(ISPICKVAL(Status__c, 'Nova'))) ))
